  ('police-f3743df6-moex-00003', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依司法院大法官解釋，大陸地區人民於臺灣地區設籍未滿 10 年者，不得擔任公務人員之規 定，並未牴觸憲法，下列敘述何者錯誤？', '["立法者制定規範時應斟酌事物本質的差異而為合理的區別對待，以實現憲法價值", "法律得基於原大陸地區人民對自由民主憲政體制的認識與其他臺灣人民可能不同，限制其 任公職之權利", "此類爭議涉及兩岸政治事務，故對於代表民意且充分掌握資訊的立法機關，司法機關應完 全尊重其決定", "設籍10年始得任公職的限制，仍在必要及合理的範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
